@app.route("/documents", methods=["GET"])
def query_documents():
    try:
        query = {}

        title = request.args.get("title")
        status = request.args.get("status")
        category = request.args.get("category")
        tag = request.args.get("tag")
        author_id = request.args.get("author_id")
        min_views = request.args.get("min_views")
        max_views = request.args.get("max_views")

        if title:
            query["title"] = {"$regex": title, "$options": "i"}
        if status:
            query["status"] = status
        if category:
            query["category"] = category
        if tag:
            query["tags"] = tag
        if author_id:
            author_oid = parse_object_id(author_id)
            if not author_oid:
                return jsonify({"error": "Invalid author_id"}), 400
            query["author_id"] = author_oid

        if min_views or max_views:
            query["views"] = {}
            if min_views is not None:
                query["views"]["$gte"] = int(min_views)
            if max_views is not None:
                query["views"]["$lte"] = int(max_views)

        sort_by = request.args.get("sort_by", "created_at")
        sort_order = request.args.get("sort_order", "desc")
        limit = int(request.args.get("limit", 50))
        skip = int(request.args.get("skip", 0))

        direction = -1 if sort_order.lower() == "desc" else 1

        docs = list(
            documents_collection.find(query)
            .sort(sort_by, direction)
            .skip(skip)
            .limit(limit)
        )

        return jsonify([serialize_document(doc) for doc in docs]), 200
    except ValueError:
        return jsonify({"error": "Invalid numeric query parameter"}), 400
    except PyMongoError as e:
        return jsonify({"error": "Database error", "message": str(e)}), 500


